/*
 * asinf() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly asinf  (test_asinf_opt.elf)
 *   2. Linked with toolchain's default asinf        (test_asinf_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint32_t f2u(float f)
{
    union { float f; uint32_t u; } x;
    x.f = f;
    return x.u;
}

static inline float u2f(uint32_t u)
{
    union { float f; uint32_t u; } x;
    x.u = u;
    return x.f;
}

#ifdef EN_PERF
static volatile float g_acc;

static void emit(float x)
{
    volatile float vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += asinf(vx);
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#else
static void emit(float x)
{
    float r = asinf(x);
    printf("%08lx %08lx\n", (unsigned long)f2u(x), (unsigned long)f2u(r));
}

static void emit_u(uint32_t bits)
{
    emit(u2f(bits));
}
#endif

/* ------------------------------------------------------------------ */
/* 100 representative test points for asinf                           */
/* Domain: [-1, 1]; inputs outside return NaN (domain error)          */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0f);
    emit(-0.0f);
    emit_u(0x7fc00000u);  /* qNaN */
    emit_u(0x7f800001u);  /* sNaN */
    emit_u(0xffc00000u);  /* -qNaN */
    emit_u(0x7f800000u);  /* +Inf (out of domain) */
    emit_u(0xff800000u);  /* -Inf (out of domain) */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x00000001u);  /* min positive subnormal: 2^-149 */
    emit_u(0x80000001u);  /* min negative subnormal: -2^-149 */
    emit_u(0x00400000u);  /* mid positive subnormal */
    emit_u(0x80400000u);  /* mid negative subnormal */
    emit_u(0x007fffffu);  /* max positive subnormal: just below FLT_MIN */
    emit_u(0x807fffffu);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(FLT_MIN);                /* 2^-126, smallest normal positive */
    emit(-FLT_MIN);               /* smallest normal negative */
    emit_u(0x00800001u);          /* one ULP above FLT_MIN */
    emit_u(0x7f7fffffu);          /* FLT_MAX: out of domain, returns NaN */
    emit_u(0xff7fffffu);          /* -FLT_MAX: out of domain, returns NaN */
    emit_u(0x7f7ffffeu);          /* one ULP below FLT_MAX, also out of domain */

    /* --- Section 4: Near +1.0 and -1.0 ULP neighbors (8) --- */
    emit_u(0x3f7ffffeu);  /* two ULPs below 1.0: ~0.9999998 */
    emit_u(0x3f7fffffu);  /* one ULP below 1.0: ~0.9999999 */
    emit_u(0x3f800000u);  /* exactly 1.0: asinf(1.0) = pi/2 */
    emit_u(0x3f800001u);  /* one ULP above 1.0: out of domain */
    emit_u(0xbf800001u);  /* one ULP away from zero past -1.0: out of domain */
    emit_u(0xbf800000u);  /* exactly -1.0: asinf(-1.0) = -pi/2 */
    emit_u(0xbf7fffffu);  /* one ULP toward zero from -1.0: ~-0.9999999 */
    emit_u(0xbf7ffffeu);  /* two ULPs toward zero from -1.0: ~-0.9999998 */

    /* --- Section 5: Exponent switching near 0.5 boundary (6) --- */
    /* asinf switches polynomial branch at |x| = 0.5 */
    emit_u(0x3effffffu);  /* one ULP below 0.5 */
    emit_u(0x3f000000u);  /* exactly 0.5: asinf(0.5) = pi/6 */
    emit_u(0x3f000001u);  /* one ULP above 0.5 */
    emit_u(0xbeffffffu);  /* one ULP toward zero from -0.5 */
    emit_u(0xbf000000u);  /* exactly -0.5: asinf(-0.5) = -pi/6 */
    emit_u(0xbf000001u);  /* one ULP away from zero past -0.5 */

    /* --- Section 6: Known mathematical values (14) --- */
    /* asinf(0.5)   = pi/6  ~ 0.5236 rad (30 deg) */
    /* asinf(sqrt2/2) = pi/4 ~ 0.7854 rad (45 deg) */
    /* asinf(sqrt3/2) = pi/3 ~ 1.0472 rad (60 deg) */
    emit(0.5f);
    emit(-0.5f);
    emit_u(0x3f3504f3u);   /* sqrt(2)/2 ~ 0.70710678: asinf = pi/4 */
    emit_u(0xbf3504f3u);   /* -sqrt(2)/2 */
    emit_u(0x3f6ed9f0u);   /* sqrt(3)/2 ~ 0.86602540: asinf = pi/3 */
    emit_u(0xbf6ed9f0u);   /* -sqrt(3)/2 */
    emit(0.1f);
    emit(-0.1f);
    emit(0.25f);
    emit(-0.25f);
    emit(0.75f);
    emit(-0.75f);
    emit(0.9f);
    emit(-0.9f);

    /* --- Section 7: Tiny-argument fast-path thresholds (8) --- */
    /* For |x| << 1, asinf(x) ~ x; test near implementation thresholds */
    emit_u(0x39800000u);   /* 2^-12 ~ 2.44e-4 */
    emit_u(0xb9800000u);   /* -2^-12 */
    emit_u(0x33800000u);   /* 2^-24 ~ 5.96e-8, near float epsilon */
    emit_u(0xb3800000u);   /* -2^-24 */
    emit(1.0e-10f);
    emit(-1.0e-10f);
    emit(1.0e-20f);
    emit(-1.0e-20f);

    /* --- Section 8: Dense coverage near polynomial branch boundary (9) --- */
    /* Several ULPs around 0.5 and -0.5 to stress the branch transition */
    emit_u(0x3efffffeu);   /* two ULPs below 0.5 */
    emit_u(0x3f000002u);   /* two ULPs above 0.5 */
    emit_u(0x3f000008u);   /* eight ULPs above 0.5 */
    emit_u(0xbefffffeu);   /* two ULPs toward zero from -0.5 */
    emit_u(0xbf000002u);   /* two ULPs away from zero past -0.5 */
    emit_u(0xbf000008u);   /* eight ULPs past -0.5 */
    /* Also stress near 1/sqrt(2) = 0.707..., another common branch point */
    emit_u(0x3f3504f2u);   /* one ULP below sqrt(2)/2 */
    emit_u(0x3f3504f4u);   /* one ULP above sqrt(2)/2 */
    emit_u(0x3f3504f0u);   /* several ULPs below sqrt(2)/2 */

    /* --- Section 9: Evenly spaced coverage across domain (14) --- */
    emit(-0.99f);
    emit(-0.95f);
    emit(-0.8f);
    emit(-0.6f);
    emit(-0.4f);
    emit(-0.3f);
    emit(-0.2f);
    emit(-0.05f);
    emit(0.05f);
    emit(0.2f);
    emit(0.3f);
    emit(0.4f);
    emit(0.6f);
    emit(0.8f);

    /* --- Section 10: Out-of-domain and hard boundary cases (22) --- */
    /* All inputs with |x| > 1 must return NaN */
    emit(1.5f);
    emit(-1.5f);
    emit(2.0f);
    emit(-2.0f);
    emit(10.0f);
    emit(-10.0f);
    emit(100.0f);
    emit(-100.0f);
    emit_u(0x3f800002u);   /* two ULPs above 1.0: out of domain */
    emit_u(0xbf800002u);   /* two ULPs below -1.0: out of domain */
    /* Near-boundary: just inside ±1 at increasing distances */
    emit(0.999f);
    emit(-0.999f);
    emit(0.9999f);
    emit(-0.9999f);
    emit(0.99999f);
    emit(-0.99999f);
    emit(0.999999f);
    emit(-0.999999f);
    /* Exact domain edge bit patterns */
    emit_u(0x3f7ffff0u);   /* 16 ULPs below 1.0 */
    emit_u(0x3f7fffe0u);   /* 32 ULPs below 1.0 */
    emit_u(0xbf7ffff0u);   /* 16 ULPs toward zero from -1.0 */
    emit_u(0xbf7fffe0u);   /* 32 ULPs toward zero from -1.0 */
}

/* --- Dense sweep and exhaustive small-range tests (accuracy path only) --- */

#ifndef EN_PERF
/* Sweep [-1, 1] in 200 steps */
static void test_sweep(void)
{
    int nsteps = 200;
    for (int i = 0; i <= nsteps; i++)
        emit(-1.0f + 2.0f * (float)i / (float)nsteps);
}

/* Exhaustive [-1, 1] every 65536 ULP */
static void test_exhaustive_small(void)
{
    uint32_t start = 0xbf800000u; /* -1.0 */
    uint32_t end = 0x3f800000u;   /* 1.0 */
    for (uint32_t b = start; b <= end; b += 65536) {
        if (b >= start && b <= end)
            emit_u(b);
    }
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %08lx\n", (unsigned long)f2u((float)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

